async function testGetWeatherValidation() {
  const BASE = 'http://localhost:3001';

  // Test missing parameters — schema validation returns 400
  const res1 = await fetch(`${BASE}/api/weather`);
  assertEquals(res1.status, 400, 'Missing params should return 400');
  const body1 = await res1.json();
  assert(body1.error, 'Should have error field');

  // Test missing lon — schema validation returns 400
  const res2 = await fetch(`${BASE}/api/weather?lat=43.3`);
  assertEquals(res2.status, 400, 'Missing lon should return 400');

  // Test valid coordinates — should return 200 with weather data
  const res3 = await fetch(`${BASE}/api/weather?lat=43.3&lon=5.37`);
  assertEquals(res3.status, 200, 'Valid coordinates should return 200');
  const body3 = await res3.json();
  assert(body3.current !== undefined, 'Should have current conditions');
  assert(body3.hourly !== undefined, 'Should have hourly forecast');
}
